PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT ?cancer ?method WHERE {
  VALUES ?cancer {
    wd:Q128581 wd:Q188874 wd:Q47912 wd:Q160105
  }
  {
    ?cancer wdt:P11738 ?method
  } UNION {
    ?cancer wdt:P2176 ?method
  } UNION {
    ?cancer wdt:P4954 ?method
  }
}

